def validate_item(item):
    return item['price'] > 0

def calculate_total(items):
    return sum(item['price'] for item in items)

def process_order(order):
    valid_items = [item for item in order['items'] if validate_item(item)]

    total_price = calculate_total(valid_items)

    print(f"Processing order {order['id']} with a total of ${total_price:.2f}")
    return total_price

# Sample data
orders = [
    {
        "id": "ORD-123",
        "items": [
            {"name": "Laptop", "price": 1200.00, "quantity": 1},
            {"name": "Mouse", "price": 25.00, "quantity": 2},
        ],
    },
    {
        "id": "ORD-456",
        "items": [
            {"name": "Keyboard", "price": -75.00, "quantity": 1},
            {"name": "Webcam", "price": 50.00, "quantity": 1},
        ],
    },
]

# Process all orders
for order_data in orders:
    process_order(order_data)

